from __future__ import annotations
import statistics
def apply(metrics,invariance,coverage,noninferiority):
    window=lambda m:m["macro_f1"]>=.75 and m["balanced_accuracy"]>=.80 and m["benign_recall"]>=.75 and m["FPR"]<=.25 and m["attack_macro_recall"]>=.80 and not m["zero_recall_classes"]
    state=lambda m:m["candidate_evidence_recall"]>=.85 and m["strong_evidence_precision"]>=.90 and m["stateful"]["duplicate_suppression_precision"]>=.99 and m["stateful"]["duplicate_false_suppression_count"]==0 and m["stateful"]["first_alert_suppression_count"]==0 and m["stateful"]["eligible_but_not_emitted_count"]==0 and m["stateful"]["state_machine_extra_delay_count"]==0 and m["stateful"]["cross_run_contamination_count"]==0 and m["stateful"]["cross_activity_contamination_count"]==0 and m["stateful"]["review_window_rate"]<=.25 and m["stateful"]["attack_review_window_rate"]<=.35 and m["stateful"]["pre_alert_pending_attack_window_rate"]<=.35
    episode=lambda m:m["episode"]["attack_episode_recall"]>=.85 and m["episode"]["episode_alert_precision"]>=.90 and m["episode"]["benign_episode_false_alert_rate"]<=.10 and m["episode"]["detection_by_second_window"]>=.75 and m["episode"]["unresolved_pending_episode_rate"]<=.15 and min(m["episode"]["per_class_episode_recall"].values())>=.666667
    values=list(metrics.values()); catastrophic=sum(m["macro_f1"]<.5 or m["benign_recall"]<.5 or m["FPR"]>.5 or m["attack_macro_recall"]<.5 for m in values)
    aggregate={"median_macro_f1":statistics.median(m["macro_f1"] for m in values),"minimum_macro_f1":min(m["macro_f1"] for m in values),"median_balanced_accuracy":statistics.median(m["balanced_accuracy"] for m in values),"minimum_balanced_accuracy":min(m["balanced_accuracy"] for m in values),"median_benign_recall":statistics.median(m["benign_recall"] for m in values),"minimum_benign_recall":min(m["benign_recall"] for m in values),"median_FPR":statistics.median(m["FPR"] for m in values),"maximum_FPR":max(m["FPR"] for m in values),"median_attack_macro_recall":statistics.median(m["attack_macro_recall"] for m in values),"minimum_attack_macro_recall":min(m["attack_macro_recall"] for m in values),"median_attack_episode_recall":statistics.median(m["episode"]["attack_episode_recall"] for m in values),"minimum_attack_episode_recall":min(m["episode"]["attack_episode_recall"] for m in values),"median_episode_precision":statistics.median(m["episode"]["episode_alert_precision"] for m in values),"minimum_episode_precision":min(m["episode"]["episode_alert_precision"] for m in values),"median_benign_episode_FAR":statistics.median(m["episode"]["benign_episode_false_alert_rate"] for m in values),"maximum_benign_episode_FAR":max(m["episode"]["benign_episode_false_alert_rate"] for m in values),"median_detection_by_second":statistics.median(m["episode"]["detection_by_second_window"] for m in values),"minimum_detection_by_second":min(m["episode"]["detection_by_second_window"] for m in values),"median_unresolved_pending_rate":statistics.median(m["episode"]["unresolved_pending_episode_rate"] for m in values),"maximum_unresolved_pending_rate":max(m["episode"]["unresolved_pending_episode_rate"] for m in values),"catastrophic_benchmark_count":catastrophic}
    aggregate_pass=aggregate["median_macro_f1"]>=.90 and aggregate["minimum_macro_f1"]>=.75 and aggregate["median_balanced_accuracy"]>=.90 and aggregate["minimum_balanced_accuracy"]>=.80 and aggregate["median_benign_recall"]>=.90 and aggregate["minimum_benign_recall"]>=.75 and aggregate["median_FPR"]<=.10 and aggregate["maximum_FPR"]<=.25 and aggregate["median_attack_macro_recall"]>=.90 and aggregate["minimum_attack_macro_recall"]>=.80 and aggregate["median_attack_episode_recall"]>=.90 and aggregate["minimum_attack_episode_recall"]>=.85 and aggregate["median_episode_precision"]>=.95 and aggregate["minimum_episode_precision"]>=.90 and aggregate["median_benign_episode_FAR"]<=.05 and aggregate["maximum_benign_episode_FAR"]<=.10 and aggregate["median_detection_by_second"]>=.90 and aggregate["minimum_detection_by_second"]>=.75 and aggregate["median_unresolved_pending_rate"]<=.10 and aggregate["maximum_unresolved_pending_rate"]<=.15 and catastrophic==0
    flags={"all_absolute_window_gates_passed":all(window(m) for m in values),"all_stateful_gates_passed":all(state(m) for m in values),"all_episode_gates_passed":all(episode(m) for m in values),"cross_benchmark_aggregate_policy_passed":aggregate_pass,"scientific_coverage_policy_passed":coverage,"non_inferiority_policy_passed":noninferiority,"catastrophic_regression_absent":catastrophic==0,"calibration_regression_policy_passed":all(m["calibration"]["joint_ece"]<=.10 and m["calibration"]["joint_brier"]<=.10 for m in values),"conformal_regression_policy_passed":all(m["conformal"]["empirical_coverage_overall"]>=.80 and m["conformal"]["wrong_only_rate"]<=.10 for m in values),"duplicate_suppression_policy_passed":all(m["stateful"]["duplicate_suppression_precision"]>=.99 and m["stateful"]["duplicate_false_suppression_count"]==0 for m in values),"state_machine_consistency_passed":all(m["stateful"]["state_machine_consistency_passed"] for m in values),"all_causal_order_invariance_passed":all(x["causal_order_invariance_passed"] for x in invariance.values())}
    return flags,aggregate
